-- Idées déjà livrées dans les versions précédentes → done
UPDATE ideas SET status = 'done' WHERE title IN (
  'Commentaires enrichis',
  'Carte heatmap',
  'Notifications push',
  'Gamification citoyenne',
  'Classement citoyens',
  'App mobile React Native',
  'Mode hors-ligne'
);

-- Idées livrées dans cette session → done
UPDATE ideas SET status = 'done' WHERE title IN (
  'Tableau de bord citoyen',
  'Tableau de bord admin avancé'
);

-- Idées en cours / partiellement livrées → in_progress
UPDATE ideas SET status = 'in_progress' WHERE title IN (
  'Accessibilité inclusive (RGAA)',
  'Export données CSV/PDF'
);

SELECT id, title, status FROM ideas ORDER BY id;

